sql:
SELECT name
FROM birth_records
WHERE births > 500 AND year = 2020 AND region_id = 1;

SELECT br.name, ns.synonym, ns.source
FROM birth_records br
JOIN name_synonyms ns ON br.name = ns.name;

SELECT name, AVG(popularity_index) AS avg_popularity_index
FROM name_trends
GROUP BY name;

external_knowledge:
This question requires external knowledge to understand the concept of 'yearly birth totals' and how they relate to the provided data; 
the phrase 'listed in chronological order' implies sorting by year in ascending order (earliest year first); 
the phrase 'with the regions having the most births appearing first' implies sorting by total births in descending order (highest total births first) within each year.

sql:
SELECT br.region_id, br.year, SUM(br.births) AS total_births
FROM birth_records br
GROUP BY br.region_id, br.year;

SELECT total_births, female_births, male_births
FROM birth_statistics
WHERE year_id = (SELECT year_id FROM years WHERE year = 2020);

SELECT br.region_id, br.year, COUNT(br.record_id) AS total_births
FROM birth_records br
GROUP BY br.region_id, br.year;

SELECT name, year, births
FROM birth_records
ORDER BY births DESC;

SELECT COUNT(DISTINCT br.name) AS count_of_unique_edited_names
FROM birth_records br
INNER JOIN version_control vc ON br.record_id = vc.record_id;
